// Martial PC creature minis — now generated by the procedural miniature engine
// ($lib/minis) via the fromRecipe() adapter. Each ModelDef keeps its stable id /
// label / icon / color / category / keywords (pickMiniId, the Figures panel and
// the auto NPC catalog all key off those) and swaps only its `build` for a
// compact recipe: class + species + gear + pose. The engine owns every
// sculptural decision, so these read as one premium product line instead of a
// bag of hand-placed boxes.
//
// EXCEPTION: `mounted-knight` is still hand-built — a rider-on-quadruped-mount
// composite has no representation in the biped recipe system (see
// docs/miniature-generator.md). Everything else is a recipe.
import { C } from './kit.ts';
import type { ModelDef, ModelBuild } from './types.ts';
import { fromRecipe } from './miniRecipe.ts';

// A round shield held on the left arm (mounted-knight only — recipe minis get
// their shields from the gear library). Placed in front of the left hand so the
// arm presses against its back instead of poking through the face.
const shield = (k: Parameters<ModelBuild>[0], color: string | number, bulk = 1) => {
  const x = -0.225 * bulk, z = 0.06 + 0.055 * bulk;
  return k.group(
    k.rot(k.cyl(0.18, 0.18, 0.04, color, x, 0.55, z, 18), Math.PI / 2),
    k.sph(0.045, C.STEEL, x, 0.55, z + 0.03),
  );
};

