      const g = k.group();
      // Simple horse body under the rider.
      const horse = 0x6b4a32;
      g.add(k.rot(k.cap(0.22, 0.6, horse, 0, 0.6, 0), 0, 0, Math.PI / 2)); // barrel
      g.add(k.box(0.36, 0.3, 0.18, horse, 0, 0.55, -0.46)); // hindquarters
      g.add(k.rot(k.cyl(0.1, 0.13, 0.4, horse, 0.04, 0.78, 0.4), -0.5, 0, 0)); // neck
      g.add(k.box(0.13, 0.16, 0.26, horse, 0.04, 0.95, 0.56)); // head
      for (const [x, z] of [[-0.16, 0.34], [0.16, 0.34], [-0.16, -0.34], [0.16, -0.34]] as const)
        g.add(k.cyl(0.05, 0.05, 0.6, horse, x, 0.3, z)); // legs
      g.add(k.box(0.5, 0.06, 0.34, C.LEATHER, 0, 0.78, -0.05)); // saddle
      // Knight rider, raised onto the saddle.
      const rider = k.humanoid({ body: C.STEEL, bulk: 1.15, shoulders: true });
      rider.position.set(0, 0.78, -0.05);
      rider.scale.setScalar(0.85);
      rider.add(k.sph(0.14, C.STEEL, 0, 0.92, 0)); // helmet
      rider.add(k.cone(0.05, 0.12, color, 0, 1.06, 0)); // crest
      rider.add(k.cyl(0.018, 0.018, 1.0, C.DARKWOOD, 0.24, 0.5, 0.2)); // lance haft
